export default function Project({ title, description, image }) {
  return (
    <div className="project-card" style={{ backgroundImage: `url(${image})` }}>
      <div className="project-card-inner">
        <div className="project-card-content">
          <h4>{title}</h4>
          <p>{description}</p>
          <button type="button" className="project-card-btn">
            See more
          </button>
        </div>
      </div>
    </div>
  );
}
